/// <summary>
///
/// </summary>
public void executeQuery()
{
    //Query registros no tratados
    QueryBuildDataSource qbds = this.query().dataSourceTable(tableNum(KPMGCommon_SalesInvoiceFas5));
    qbds.clearRanges();

    QueryBuildRange TreatedRange = qbds.addRange(fieldNum(KPMGCommon_SalesInvoiceFas5, Treated));

    if (ShowAllCheckBoxFilter.checked())
    {
        qbds.clearRanges();
    }
    else{
        TreatedRange.value(queryValue(NoYes::No));
    }

    super();
}

