private void createSalesInvoiceFas5Error(KPMGCommon_SalesInvoiceFas5 salesInvoiceFas5, Description1000 ErrorDescription)
{
    KPMGCommon_SalesInvoiceFas5Error salesInvoiceFas5Error;

    salesInvoiceFas5Error.InvoiceId = salesInvoiceFas5.InvoiceId;
    salesInvoiceFas5Error.CContable = salesInvoiceFas5.CContable;
    salesInvoiceFas5Error.RefRecId = salesInvoiceFas5.RecId;
    salesInvoiceFas5Error.RefTableId = salesInvoiceFas5.TableId;
    salesInvoiceFas5Error.DescriptionError = ErrorDescription;
    salesInvoiceFas5Error.Corrected = NoYes::No;
    salesInvoiceFas5Error.Periodo = KPMGCommon_Period::New;

    salesInvoiceFas5Error.insert();

    Message::Add(MessageSeverity::Error, strFmt("@KPMGCommon:SalesInvoiceFas5_ErrorMessage", salesInvoiceFas5.InvoiceId, salesInvoiceFas5.NumLine, ErrorDescription));

}

private void checkErrorInInvoice(boolean invoiceError, String20 invoiceId)
{
