/// <summary>
///
/// </summary>
public void clicked()
{
    KPMGCommon_SalesInvoiceFas5 salesInvoiceFas5;
    FormDataSource      salesInvoiceFas5_ds;
    FormRun             formRun;

    formRun = this.formRun();
    salesInvoiceFas5_ds = formRun.dataSource("KPMGCommon_SalesInvoiceFas5");
    salesInvoiceFas5 = salesInvoiceFas5_ds.cursor();
    if(!salesInvoiceFas5.Treated)
    {
        super();
        KPMGCommon_SalesInvoiceFas5_ds.reread();
    }
}
